const ACCOUNT_ID = '9231063';
const CONSUMER_KEY = '9129dd37d3564cc47cf6faf331d0cbc84266b0bab347c2e94fb428b7cb9b3a0a';
const CONSUMER_SECRET = '157e69200b8504dc6133f28b81025a96755a2b81f4acde7d66538f561687ffc6';
const TOKEN_ID = 'bb9ee805f466c066d3a0b3027d70fee9f9a6219c7e635d25095ec0f38ecd568a';
const TOKEN_SECRET = 'd27eabcb80decf6fd5b8a5c4914617972157875458eb15dbfa9fbb32db8af5ca';

const projectId = $input.item.json.projectId;
if (!projectId) {
  return { json: { error: 'projectId query param required' } };
}

const baseUrl = `https://${ACCOUNT_ID}.suitetalk.api.netsuite.com/services/rest/query/v1/suiteql`;
const limit = 1000;
const offset = $input.item.json.offset || 0;
const fullUrl = `${baseUrl}?limit=${limit}&offset=${offset}`;

const crypto = require('crypto');
const oauth_nonce = crypto.randomBytes(16).toString('hex');
const oauth_timestamp = Math.floor(Date.now() / 1000).toString();

const queryParams = { limit: limit.toString(), offset: offset.toString() };
const oauthParams = {
  oauth_consumer_key: CONSUMER_KEY,
  oauth_nonce,
  oauth_signature_method: 'HMAC-SHA256',
  oauth_timestamp,
  oauth_token: TOKEN_ID,
  oauth_version: '1.0'
};

const allParams = { ...queryParams, ...oauthParams };
const paramString = Object.keys(allParams)
  .sort()
  .map(key => `${encodeURIComponent(key)}=${encodeURIComponent(allParams[key])}`)
  .join('&');

const signatureBaseString = ['POST', encodeURIComponent(baseUrl), encodeURIComponent(paramString)].join('&');
const signingKey = `${encodeURIComponent(CONSUMER_SECRET)}&${encodeURIComponent(TOKEN_SECRET)}`;
const oauth_signature = crypto.createHmac('sha256', signingKey).update(signatureBaseString).digest('base64');

const authHeader =
  `OAuth realm="${ACCOUNT_ID}", ` +
  `oauth_consumer_key="${CONSUMER_KEY}", ` +
  `oauth_token="${TOKEN_ID}", ` +
  `oauth_signature_method="HMAC-SHA256", ` +
  `oauth_timestamp="${oauth_timestamp}", ` +
  `oauth_nonce="${oauth_nonce}", ` +
  `oauth_version="1.0", ` +
  `oauth_signature="${encodeURIComponent(oauth_signature)}"`;

const query = `SELECT t.id AS internal_id, t.tranId AS oc_number, t.tranDate AS fecha, BUILTIN.DF(t.status) AS estatus, t.entity AS vendor_id, BUILTIN.DF(t.entity) AS vendor_code, BUILTIN.DF(t.custbody_bb_project) AS proyecto, BUILTIN.DF(t.currency) AS moneda, t.exchangeRate AS tipo_cambio, t.total AS monto_total, t.memo AS nota FROM purchaseOrder t WHERE t.custbody_bb_project = ${projectId} AND t.status IN ('B','E','F') ORDER BY t.tranDate DESC`;

return {
  json: {
    url: fullUrl,
    authHeader,
    body: { q: query },
    offset
  }
};

const raw = $input.first().json;
let parsed;
try {
  parsed = typeof raw.data === 'string' ? JSON.parse(raw.data) : raw;
} catch (e) {
  return { json: { error: 'PARSE_FAILED', message: e.message } };
}

const items = parsed.items || [];

const oc_list = items.map(r => ({
  internal_id: r.internal_id,
  oc_number: r.oc_number,
  fecha: r.fecha,
  estatus: r.estatus,
  vendor_id: r.vendor_id,
  vendor_code: r.vendor_code,
  moneda: r.moneda,
  tipo_cambio: r.tipo_cambio ? parseFloat(r.tipo_cambio) : null,
  monto_total: r.monto_total ? parseFloat(r.monto_total) : 0,
  nota: r.nota
}));

// Extraer vendor_ids únicos para que el frontend los resuelva
const unique_vendors = [...new Set(items.map(r => r.vendor_id).filter(Boolean))];

return {
  json: {
    oc_list,
    unique_vendors,
    hasMore: parsed.hasMore
  }
};
